using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Returns the value of a configuration key.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up (e.g. 'AppName', 'MaxRetries')")] string key)
    {
        var config = AppConfig.Current;
        return config.TryGetValue(key, out var value)
            ? value
            : $"Key '{key}' not found. Available keys: {string.Join(", ", config.Keys)}";
    }

    [McpServerTool, Description("Lists all available configuration keys.")]
    public static string ListConfigKeys()
    {
        return string.Join(", ", AppConfig.Current.Keys);
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the full application configuration as JSON.")]
    public static string GetAppConfig()
    {
        return JsonSerializer.Serialize(AppConfig.Current, AppConfig.JsonOptions);
    }

    [McpServerResource(
        UriTemplate = "config://app/{section}",
        Name = "Configuration Section",
        MimeType = "application/json"),
     Description("Returns a specific configuration section by name.")]
    public static string GetConfigSection(string section)
    {
        var sectionData = AppConfig.Current
            .Where(kv => kv.Key.StartsWith(section, StringComparison.OrdinalIgnoreCase))
            .ToDictionary(kv => kv.Key, kv => kv.Value);

        return sectionData.Count > 0
            ? JsonSerializer.Serialize(sectionData, AppConfig.JsonOptions)
            : JsonSerializer.Serialize(new { error = $"Section '{section}' not found" });
    }
}

using System.Text.Json;

public static class AppConfig
{
    public static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    public static Dictionary<string, string> Current { get; } = new()
    {
        ["AppName"] = "ConfigMcpServer",
        ["Version"] = "1.0.0",
        ["Environment"] = "Development",
        ["MaxRetries"] = "3",
        ["Logging.Level"] = "Information",
        ["Logging.Format"] = "json",
        ["Database.ConnectionTimeout"] = "30",
        ["Database.MaxPoolSize"] = "100"
    };
}

